     5→//! Notch command - JJ-aware commit with heat/pace context prefix
     6→//!
     7→//! This module handles the jjx_notch command which performs a staged commit
     8→//! with heat/pace context prefix. It accepts explicit file list and generates
     9→//! a JJ context-aware commit message.
    10→
    11→use clap::Args;
    12→use std::collections::HashSet;
    13→use std::process::Command;
    14→
    15→use crate::jjrf_favor::{jjrf_Coronet as Coronet, jjrf_Firemark as Firemark, JJRF_FIREMARK_PREFIX, JJRF_CORONET_PREFIX};
    16→use crate::jjrn_notch::{jjrn_format_notch_prefix, JJRN_COMMIT_PREFIX};
    17→
    18→/// Arguments for jjx_notch command
    19→#[derive(Args, Debug)]
    20→pub struct jjrnc_NotchArgs {
    21→    /// Identity: Coronet (5-char, pace-affiliated) or Firemark (2-char, heat-only)
    22→    pub identity: String,
    23→
    24→    /// Files to commit (required, at least one)
    25→    #[arg(required = true)]
    26→    pub files: Vec<String>,
    27→
    28→    /// Size limit in bytes (overrides default 50KB guard)
    29→    #[arg(long)]
    30→    pub size_limit: Option<u64>,
    31→
    32→    /// User-provided commit message intent (overrides haiku-generated message)
    33→    #[arg(long)]
    34→    pub intent: Option<String>,
    35→}
    36→
    37→/// Run the notch command
    38→///
    39→/// Stages specified files and commits with JJ-aware prefix.
    40→/// Supports both pace-affiliated (Coronet) and heat-only (Firemark) commits.
    41→pub fn jjrnc_run_notch(args: jjrnc_NotchArgs) -> i32 {
    42→    // Require non-empty files list
    43→    if args.files.is_empty() {
    44→        eprintln!("jjx_notch: error: at least one file required");
    45→        return 1;
    46→    }
    47→
    48→    // Check each file exists
    49→    for file in &args.files {
    50→        if !std::path::Path::new(file).exists() {
    51→            eprintln!("jjx_notch: error: file does not exist: {}", file);
    52→            return 1;
    53→        }
    54→    }
    55→
    56→    // Parse identity - support both Coronet (5 chars) and Firemark (2 chars)
    57→    let identity = args.identity.strip_prefix(JJRF_CORONET_PREFIX).or_else(|| args.identity.strip_prefix(JJRF_FIREMARK_PREFIX)).unwrap_or(&args.identity);
    58→
    59→    let message = if identity.len() == 5 {
    60→        // Coronet - pace-affiliated commit
    61→        let coronet = match Coronet::jjrf_parse(&args.identity) {
    62→            Ok(c) => c,
    63→            Err(e) => {
    64→                eprintln!("jjx_notch: error: {}", e);
    65→                return 1;
    66→            }
    67→        };
    68→        jjrn_format_notch_prefix(&coronet)
    69→    } else if identity.len() == 2 {
    70→        // Firemark - heat-only commit
    71→        let firemark = match Firemark::jjrf_parse(&args.identity) {
    72→            Ok(fm) => fm,
    73→            Err(e) => {
    74→                eprintln!("jjx_notch: error: {}", e);
    75→                return 1;
    76→            }
    77→        };
    78→        let hallmark = vvc::vvcc_get_hallmark();
    79→        let identity_str = format!("{}{}", JJRF_FIREMARK_PREFIX, firemark.jjrf_as_str());
    80→        vvc::vvcc_format_branded(JJRN_COMMIT_PREFIX, &hallmark, &identity_str, "n", "", None)
    81→    } else {
    82→        eprintln!("jjx_notch: error: identity must be Coronet (5 chars) or Firemark (2 chars), got {} chars", identity.len());
    83→        return 1;
    84→    };
    85→
    86→    // Warn about uncommitted changes outside the file list
    87→    let output = match Command::new("git")
    88→        .args(["status", "--porcelain"])
    89→        .output()
    90→    {
    91→        Ok(o) => o,
    92→        Err(e) => {
    93→            eprintln!("jjx_notch: error: failed to run git status: {}", e);
    94→            return 1;
    95→        }
    96→    };
    97→
    98→    if !output.status.success() {
    99→        eprintln!("jjx_notch: error: git status failed");
   100→        return 1;
   101→    }
   102→
   103→    let status_output = String::from_utf8_lossy(&output.stdout);
   104→    let files_set: HashSet<_> = args.files.iter().map(|s| s.as_str()).collect();
   105→    let mut warnings = Vec::new();
   106→
   107→    for line in status_output.lines() {
   108→        if line.len() < 4 {
   109→            continue;
   110→        }
   111→        // Parse git status --porcelain format: "XY filename"
   112→        let filepath = &line[3..];
   113→        if !files_set.contains(filepath) {
   114→            warnings.push(format!("  {}", line));
   115→        }
   116→    }
   117→
   118→    if !warnings.is_empty() {
   119→        eprintln!("warning: uncommitted changes outside file list:");
   120→        for warning in warnings {
   121→            eprintln!("{}", warning);
   122→        }
   123→    }
   124→
   125→    // Stage only the specified files
   126→    let mut git_add = Command::new("git");
   127→    git_add.arg("add");
   128→    for file in &args.files {
   129→        git_add.arg(file);
   130→    }
   131→
   132→    let add_output = match git_add.output() {
   133→        Ok(o) => o,
   134→        Err(e) => {
   135→            eprintln!("jjx_notch: error: failed to run git add: {}", e);
   136→            return 1;
   137→        }
   138→    };
   139→
   140→    if !add_output.status.success() {
   141→        eprintln!("jjx_notch: error: git add failed");
   142→        return 1;
   143→    }
   144→
   145→    // Commit using vvc with the generated message prefix
   146→    // If --intent provided, use it as the message; otherwise let haiku generate it
   147→    let commit_args = if let Some(intent) = args.intent {
   148→        vvc::vvcc_CommitArgs {
   149→            prefix: None,
   150→            message: Some(format!("{}{}", message, intent)),
   151→            allow_empty: false,
   152→            no_stage: true,  // We already staged above
   153→            size_limit: args.size_limit.unwrap_or(vvc::VVCG_SIZE_LIMIT),
   154→            warn_limit: vvc::VVCG_WARN_LIMIT,
   155→        }
   156→    } else {
   157→        vvc::vvcc_CommitArgs {
   158→            prefix: Some(message),
   159→            message: None,
   160→            allow_empty: false,
   161→            no_stage: true,  // We already staged above
   162→            size_limit: args.size_limit.unwrap_or(vvc::VVCG_SIZE_LIMIT),
   163→            warn_limit: vvc::VVCG_WARN_LIMIT,
   164→        }
   165→    };
   166→
   167→    vvc::commit(&commit_args)
   168→}
   169→

